/**
 * Wallet Helper Utilities
 * 
 * Helper functions for wallet operations including UUID generation
 * and phone number formatting.
 */

import logger from '@/shared/utils/logger.js';

/**
 * Generate UUID for transaction references
 */
export const generateUUID = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
  } catch (_) { }
  const s4 = () => Math.floor((1 + Math.random()) * 0x10000).toString(16).substring(1);
  return `${s4()}${s4()}-${s4()}-${s4()}-${s4()}-${s4()}${s4()}${s4()}`;
};

/**
 * Generate Account ID
 */
export const generateAccountId = () => {
  return `ACC-${generateUUID()}`;
};

/**
 * Format phone number for API (remove leading 0, add country code if needed)
 */
export const formatPhoneForAPI = (phoneNumber, countryCode = '233') => {
  if (!phoneNumber) { return ''; }

  let phoneStr = String(phoneNumber).trim();

  // Remove leading +
  if (phoneStr.startsWith('+')) {
    phoneStr = phoneStr.substring(1);
  }

  // If doesn't start with country code, add it
  if (!phoneStr.startsWith(countryCode)) {
    if (phoneStr.startsWith('0')) {
      phoneStr = countryCode + phoneStr.substring(1);
    } else {
      phoneStr = countryCode + phoneStr;
    }
  }

  return phoneStr;
};

/**
 * Get user phone number from localStorage or profile
 */
export const getUserPhoneNumber = (userProfile = null) => {
  try {
    const userDataStr = localStorage.getItem('userData');
    if (userDataStr) {
      const userData = JSON.parse(userDataStr);
      let phoneNumber = userData.phone_number || userData.phone || userData.phoneNumber || '';

      if (!phoneNumber && userProfile) {
        phoneNumber = userProfile.phone_number || userProfile.phone || userProfile.phoneNumber || '';
      }

      if (phoneNumber) {
        return formatPhoneForAPI(phoneNumber);
      }
    }
  } catch (e) {
    // Silently fail - will be logged by caller if needed
  }
  return '';
};

/**
 * Get user ID from localStorage for x-user-id header
 * For business accounts, returns the business ID; for individual accounts, returns the user ID.
 * This matches the logic used in disbursementService.
 */
export const getUserIdFromStorage = () => {
  try {
    const raw = localStorage.getItem('userData');
    if (!raw) {
      logger.warn('No userData found in localStorage');
      return null;
    }
    const parsed = JSON.parse(raw);

    // If the logged-in user is a business contact or business member, prefer the business id
    // There are multiple shapes where business id may exist so try fallbacks
    const userType = (parsed?.usertype || parsed?.userType || '').toString().toLowerCase();
    const isBusinessContact = userType === 'business_contact' || userType === 'business';
    const isBusinessMember = userType === 'business_member';

    // For business members, extract business_id from team_members[0].teams.business_id
    if (isBusinessMember) {
      const businessId =
        parsed?.team_members?.[0]?.teams?.business_id ||
        parsed?.team_members?.[0]?.teams?.businessId ||
        null;

      if (businessId) {
        logger.debug('Using business id for recipientid header (business member)', { businessId });
        return businessId;
      }
      logger.warn('Business member detected but no business id found in team_members', { parsed });
      // fallthrough to other id fields
    }

    if (isBusinessContact) {
      const businessId =
        parsed?.businesses?.[0]?.id ||
        parsed?.business?.id ||
        parsed?.business_id ||
        parsed?.businessId ||
        null;

      if (businessId) {
        logger.debug('Using business id for recipientid header (business account)', { businessId });
        return businessId;
      }

      logger.warn('Business account detected but no business id found in userData', { parsed });
      // fallthrough to other id fields
    }

    // For individual accounts or fallback, use common id fields
    const userId = parsed?.id || parsed?.userId || parsed?.user_id || parsed?.customerId || parsed?.customer_id || null;

    if (!userId) {
      logger.error('No suitable id field found in userData', {
        availableFields: Object.keys(parsed || {}),
        userData: parsed
      });
    } else {
      logger.debug('Retrieved user ID for recipientid header', { userId });
    }

    return userId;
  } catch (error) {
    logger.warn('Unable to parse stored user data for recipientid header', { error });
    return null;
  }
};


